parameters.jsCode:
 const historicoTexto = items
  .map(i => {
    const msg = (i.json.mensagem || "")
      .replace(/\n/g, " ")
      .replace(/"/g, "'")
      .replace(/\s+/g, " ")
      .trim();

    return `${i.json.role || "user"}: ${msg}`;
  })
  .join(" | ");

return [{
  json: {
    historico: historicoTexto,
    mensagem: $('Edit Fields').first().json.conversa,
    empresa_id: $input.first().json.empresa_id
  }
}];

 const contexto = $input.first().json.choices[0].message.content ;

const historicoTexto = $('HistoricoDecisao').first().json.historico || "";
const pergunta = $('HistoricoDecisao').first().json.mensagem;

// 🔵 CONTINUAR → transformar texto em array + juntar
if (contexto === "continuar") {

  const partes = historicoTexto.split("|");

  const messages = partes.map(p => {
    const [role, ...rest] = p.split(":");
    return {
      role: role.trim(),
      content: rest.join(":").trim()
    };
  });

  // adiciona nova pergunta
  messages.push({
    role: "user",
    content: pergunta
  });

  return [{ json: { messages } }];
}



// 🟢 NOVO → só pergunta
return [{
  json: {
    messages: [
      {
        role: "user",
        content: pergunta
      }
    ]
  }
}];
